<?php
declare(strict_types=1);require __DIR__.'/../includes/bootstrap.php';require_role('admin');$page_title='Grade Records - SMIS';$rows=db_all('SELECT u.name student,s.student_number,c.name class_name,m.code,lu.name lecturer,g.coursework,g.examination,g.final_grade,g.letter_grade FROM grades g JOIN students s ON s.id=g.student_id JOIN users u ON u.id=s.user_id LEFT JOIN classes c ON c.id=s.class_id JOIN modules m ON m.id=g.module_id JOIN lecturers l ON l.id=g.lecturer_id JOIN users lu ON lu.id=l.user_id ORDER BY u.name,m.code');include __DIR__.'/../includes/header.php';?><div class="page-header"><h1>Grade Records</h1><p>Coursework, examination and automatically calculated final grades.</p></div><div class="card"><div class="card-body"><table class="table"><thead><tr><th>Student</th><th>Class</th><th>Module</th><th>Lecturer</th><th>CW /30</th><th>Exam /70</th><th>Final</th><th>Grade</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=e($r['student'])?></strong><br><small><?=e($r['student_number'])?></small></td><td><?=e($r['class_name']??'-')?></td><td><?=e($r['code'])?></td><td><?=e($r['lecturer'])?></td><td><?=$r['coursework']?></td><td><?=$r['examination']?></td><td><strong><?=$r['final_grade']?></strong></td><td><?=$r['letter_grade']?></td></tr><?php endforeach?></tbody></table></div></div><?php include __DIR__.'/../includes/footer.php';?>
